export function buildCountQuery(source: SQL | SQLWrapper, filters?: SQL<unknown>): SQL<number> {
	return sql<number>`select count(*) as count from ${source}${sql.raw(' where ').if(filters)}${filters};`;
}

edits.replacement:
	source: GelTable | SQL | SQLWrapper,
	filters?: SQL<unknown>,
